/**
 * Theme definitions for T3 Code.
 *
 * Defines the color contract and built-in themes consumed by both server and
 * web packages.  Keep this module data-only — no runtime logic beyond lookups.
 */

// ---------------------------------------------------------------------------
// Core types
// ---------------------------------------------------------------------------

/** Identifier for a built-in theme. */
export type ThemeId = "t3-light" | "t3-dark" | "t3-midnight";

/** Color slots every theme must provide. */
export interface ThemeColors {
  /** Main application background. */
  background: string;
  /** Primary text color. */
  foreground: string;
  /** Brand / accent highlight. */
  accent: string;
  /** Sidebar surface. */
  sidebar: string;
  /** Sidebar text. */
  sidebarForeground: string;
  /** Editor / main content area surface. */
  editor: string;
  /** Editor text. */
  editorForeground: string;
  /** Integrated terminal surface. */
  terminal: string;
  /** Terminal text. */
  terminalForeground: string;
  /** Status bar surface. */
  statusBar: string;
  /** Status bar text. */
  statusBarForeground: string;
}

/** A fully resolved application theme. */
export interface AppTheme {
  readonly id: ThemeId;
  readonly name: string;
  /** Whether the theme should activate the dark or light appearance mode. */
  readonly appearance: "light" | "dark";
  readonly colors: ThemeColors;
}

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

/** Ordered list of every built-in theme id. */
export const THEME_IDS: readonly ThemeId[] = ["t3-light", "t3-dark", "t3-midnight"];

export const DEFAULT_THEME_ID: ThemeId = "t3-dark";

/** Map from `ThemeColors` key → CSS custom property name set on `:root`. */
export const THEME_CSS_PROPERTIES: Readonly<Record<keyof ThemeColors, string>> = {
  background: "--t3-background",
  foreground: "--t3-foreground",
  accent: "--t3-accent",
  sidebar: "--t3-sidebar",
  sidebarForeground: "--t3-sidebar-foreground",
  editor: "--t3-editor",
  editorForeground: "--t3-editor-foreground",
  terminal: "--t3-terminal",
  terminalForeground: "--t3-terminal-foreground",
  statusBar: "--t3-statusbar",
  statusBarForeground: "--t3-statusbar-foreground",
};

// ---------------------------------------------------------------------------
// Built-in themes
// ---------------------------------------------------------------------------

export const BUILT_IN_THEMES: Readonly<Record<ThemeId, AppTheme>> = {
  "t3-light": {
    id: "t3-light",
    name: "T3 Light",
    appearance: "light",
    colors: {
      background: "#ffffff",
      foreground: "#1c1c1e",
      accent: "#7c3aed",
      sidebar: "#f5f5f7",
      sidebarForeground: "#1c1c1e",
      editor: "#ffffff",
      editorForeground: "#1c1c1e",
      terminal: "#f0f0f2",
      terminalForeground: "#1c1c1e",
      statusBar: "#f5f5f7",
      statusBarForeground: "#6b6b6f",
    },
  },
  "t3-dark": {
    id: "t3-dark",
    name: "T3 Dark",
    appearance: "dark",
    colors: {
      background: "#161618",
      foreground: "#e4e4e7",
      accent: "#8b5cf6",
      sidebar: "#1c1c1f",
      sidebarForeground: "#a1a1aa",
      editor: "#161618",
      editorForeground: "#e4e4e7",
      terminal: "#111113",
      terminalForeground: "#a1a1aa",
      statusBar: "#1c1c1f",
      statusBarForeground: "#71717a",
    },
  },
  "t3-midnight": {
    id: "t3-midnight",
    name: "T3 Midnight",
    appearance: "dark",
    colors: {
      background: "#0b1120",
      foreground: "#cbd5e1",
      accent: "#38bdf8",
      sidebar: "#0f172a",
      sidebarForeground: "#94a3b8",
      editor: "#0b1120",
      editorForeground: "#cbd5e1",
      terminal: "#070d1a",
      terminalForeground: "#94a3b8",
      statusBar: "#0f172a",
      statusBarForeground: "#64748b",
    },
  },
};

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

export function isThemeId(value: string): value is ThemeId {
  return (THEME_IDS as readonly string[]).includes(value);
}

export function getThemeById(id: ThemeId): AppTheme {
  return BUILT_IN_THEMES[id];
}

