import { createContext, useCallback, useContext, useEffect, useSyncExternalStore } from "react";
import {
  type AppTheme,
  type ThemeColors,
  type ThemeId,
  BUILT_IN_THEMES,
  DEFAULT_THEME_ID,
  THEME_CSS_PROPERTIES,
  isThemeId,
} from "@t3tools/shared/theme";

// ---------------------------------------------------------------------------
// Public types
// ---------------------------------------------------------------------------

/** User preference stored in localStorage. "system" auto-resolves via OS. */
export type ThemePreference = "system" | ThemeId;

// ---------------------------------------------------------------------------
// Module-level store (runs before React to prevent flash)
// ---------------------------------------------------------------------------

const STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

interface ThemeSnapshot {
  preference: ThemePreference;
  systemDark: boolean;
}

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange(): void {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return typeof window !== "undefined" && window.matchMedia(MEDIA_QUERY).matches;
}

function getStoredPreference(): ThemePreference {
  if (typeof window === "undefined") return DEFAULT_THEME_ID;
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw === "system") return "system";
  // Migrate legacy light/dark values from the old theme hook.
  if (raw === "light") return "t3-light";
  if (raw === "dark") return "t3-dark";
  if (raw !== null && isThemeId(raw)) return raw;
  return "system";
}

function resolveThemeId(preference: ThemePreference, systemDark: boolean): ThemeId {
  if (preference === "system") {
    return systemDark ? DEFAULT_THEME_ID : "t3-light";
  }
  return preference;
}

function applyThemeToDOM(theme: AppTheme, suppressTransitions = false): void {
  const root = document.documentElement;

  if (suppressTransitions) {
    root.classList.add("no-transitions");
  }

  // Toggle dark/light appearance class used by Tailwind.
  root.classList.toggle("dark", theme.appearance === "dark");

  // Apply every theme color as a CSS custom property on :root.
  const { colors } = theme;
  for (const key of Object.keys(THEME_CSS_PROPERTIES) as Array<keyof ThemeColors>) {
    root.style.setProperty(THEME_CSS_PROPERTIES[key], colors[key]);
  }

  // Expose current theme id for CSS attribute selectors.
  root.dataset.theme = theme.id;

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal.
    // oxlint-disable-next-line no-unused-expressions
    root.offsetHeight;
    requestAnimationFrame(() => {
      root.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash of un-themed content.
const _initialPref = getStoredPreference();
applyThemeToDOM(BUILT_IN_THEMES[resolveThemeId(_initialPref, getSystemDark())]);

// ---------------------------------------------------------------------------
// useSyncExternalStore plumbing
// ---------------------------------------------------------------------------

function getSnapshot(): ThemeSnapshot {
  const preference = getStoredPreference();
  const systemDark = preference === "system" ? getSystemDark() : false;

  if (
    lastSnapshot &&
    lastSnapshot.preference === preference &&
    lastSnapshot.systemDark === systemDark
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { preference, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  const mq = window.matchMedia(MEDIA_QUERY);
  const handleMediaChange = () => {
    const pref = getStoredPreference();
    if (pref === "system") {
      applyThemeToDOM(BUILT_IN_THEMES[resolveThemeId("system", getSystemDark())], true);
    }
    emitChange();
  };
  mq.addEventListener("change", handleMediaChange);

  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      const pref = getStoredPreference();
      const id = resolveThemeId(pref, getSystemDark());
      applyThemeToDOM(BUILT_IN_THEMES[id], true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleMediaChange);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// React context
// ---------------------------------------------------------------------------

export interface ThemeContextValue {
  /** Raw user preference ("system" or a specific ThemeId). */
  theme: ThemePreference;
  /** Persist a new preference. */
  setTheme: (next: ThemePreference) => void;
  /** Effective appearance after resolving "system". */
  resolvedTheme: "light" | "dark";
  /** Resolved theme identifier. */
  themeId: ThemeId;
  /** Full resolved theme object with colors. */
  activeTheme: AppTheme;
}

const ThemeContext = createContext<ThemeContextValue | null>(null);

export function ThemeProvider({ children }: { children: React.ReactNode }) {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);

  const themeId = resolveThemeId(snapshot.preference, snapshot.systemDark);
  const activeTheme = BUILT_IN_THEMES[themeId];

  const setTheme = useCallback((next: ThemePreference) => {
    localStorage.setItem(STORAGE_KEY, next);
    const nextId = resolveThemeId(next, getSystemDark());
    applyThemeToDOM(BUILT_IN_THEMES[nextId], true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount and whenever the resolved theme changes.
  useEffect(() => {
    applyThemeToDOM(activeTheme);
  }, [activeTheme]);

  const value: ThemeContextValue = {
    theme: snapshot.preference,
    setTheme,
    resolvedTheme: activeTheme.appearance,
    themeId,
    activeTheme,
  };

  return <ThemeContext value={value}>{children}</ThemeContext>;
}

/**
 * Read the current theme and obtain a setter.
 *
 * Must be rendered inside a `<ThemeProvider>`.
 */
export function useTheme(): ThemeContextValue {
  const ctx = useContext(ThemeContext);
  if (!ctx) {
    throw new Error("useTheme must be used within a <ThemeProvider>");
  }
  return ctx;
}

