import { BUILT_IN_THEMES, THEME_IDS, type ThemeId } from "@t3tools/shared/theme";

import { cn } from "../lib/utils";
import { useTheme, type ThemePreference } from "./ThemeProvider";

// ---------------------------------------------------------------------------
// Swatch preview — miniature visual representing the theme's colour palette
// ---------------------------------------------------------------------------

function ThemeSwatch({
  themeId,
  selected,
  onClick,
}: {
  themeId: ThemeId;
  selected: boolean;
  onClick: () => void;
}) {
  const theme = BUILT_IN_THEMES[themeId];
  const { colors } = theme;

  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      className={cn(
        "flex w-full items-start gap-3 rounded-lg border px-3 py-2.5 text-left transition-colors",
        selected
          ? "border-primary/60 bg-primary/8 text-foreground"
          : "border-border bg-background text-muted-foreground hover:bg-accent",
      )}
      onClick={onClick}
    >
      {/* Miniature layout preview */}
      <div
        className="mt-0.5 flex h-8 w-12 shrink-0 overflow-hidden rounded-md border border-border"
        aria-hidden="true"
      >
        <div className="flex w-full flex-col">
          <div className="flex flex-1">
            <div style={{ background: colors.sidebar }} className="w-1/3" />
            <div className="flex w-2/3 flex-col">
              <div style={{ background: colors.editor }} className="flex-1" />
              <div style={{ background: colors.terminal }} className="h-1/3" />
            </div>
          </div>
          <div style={{ background: colors.statusBar }} className="h-1.5" />
        </div>
      </div>

      <span className="flex flex-1 flex-col">
        <span className="text-sm font-medium">{theme.name}</span>
        <span className="text-xs capitalize">{theme.appearance} appearance</span>
      </span>

      {selected ? (
        <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
          Active
        </span>
      ) : null}
    </button>
  );
}

// ---------------------------------------------------------------------------
// System swatch — half light / half dark split preview
// ---------------------------------------------------------------------------

function SystemSwatch({
  selected,
  onClick,
}: {
  selected: boolean;
  onClick: () => void;
}) {
  const lightColors = BUILT_IN_THEMES["t3-light"].colors;
  const darkColors = BUILT_IN_THEMES["t3-dark"].colors;

  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      className={cn(
        "flex w-full items-start gap-3 rounded-lg border px-3 py-2.5 text-left transition-colors",
        selected
          ? "border-primary/60 bg-primary/8 text-foreground"
          : "border-border bg-background text-muted-foreground hover:bg-accent",
      )}
      onClick={onClick}
    >
      {/* Split light/dark preview */}
      <div
        className="mt-0.5 flex h-8 w-12 shrink-0 overflow-hidden rounded-md border border-border"
        aria-hidden="true"
      >
        <div className="flex w-full">
          <div style={{ background: lightColors.editor }} className="w-1/2" />
          <div style={{ background: darkColors.editor }} className="w-1/2" />
        </div>
      </div>

      <span className="flex flex-1 flex-col">
        <span className="text-sm font-medium">System</span>
        <span className="text-xs">Match your OS appearance setting</span>
      </span>

      {selected ? (
        <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
          Active
        </span>
      ) : null}
    </button>
  );
}

// ---------------------------------------------------------------------------
// Composite selector
// ---------------------------------------------------------------------------

export function ThemeSelector() {
  const { theme, setTheme } = useTheme();

  const handleSelect = (preference: ThemePreference) => {
    setTheme(preference);
  };

  return (
    <div className="space-y-2" role="radiogroup" aria-label="Theme preference">
      <SystemSwatch selected={theme === "system"} onClick={() => handleSelect("system")} />

      {THEME_IDS.map((id) => (
        <ThemeSwatch
          key={id}
          themeId={id}
          selected={theme === id}
          onClick={() => handleSelect(id)}
        />
      ))}
    </div>
  );
}

