import { createContext, useCallback, useContext, useEffect, useMemo, useSyncExternalStore } from "react";
import {
  type AppTheme,
  type ThemeColors,
  type ThemeId,
  BUILT_IN_THEMES,
  DEFAULT_THEME_ID,
  THEME_CSS_PROPERTIES,
